  ('dietitian-moex-10324', 'dietitian', 'dietitian-moex-095-da9d23a3', 'sub-dietitian-06', NULL, 'single_choice', '健康食品之原料，如為傳統食用而非以通常加工食品形式供食者，在安全性評估方面需符合下列那項條件？', '["得免進行毒性測試", "應檢具基因毒性試驗及28天餵食毒性試驗資料", "應檢具致畸試驗及致癌性試驗資料", "應檢具90天餵食毒性試驗及致畸試驗資料"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:56+00:00", "source_pdf_sha1": "3d09d9a5ef46", "answer_pdf_sha1": "489405e1aca8", "source_family": "moex-gov-tw", "moex": {"exam_code": "095140", "c": "112", "s": "6001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "食品衛生與安全", "year": "095", "exam_name": "095年第二次專技醫事人員、中醫師、心理師、呼吸治療師、營養師、獸醫人員考試", "original_question_number": 2, "answer_corrected": false, "flags": ["answer_missing"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
